VALUES ('tsp-loop-589', 589, 'Gridville inferred edge set', 'CLOSED', 'tsp-rule-local-bound-edge-union', 'Gridville inferred edge set', 'Derived 5 unique edges [''edge-a-b'', ''edge-a-e'', ''edge-b-c'', ''edge-c-d'', ''edge-d-e''] at total cost 14; no CandidateTour/TourStop/TourLeg row was an antecedent.', 'Prove the derived edge set is connected and degree two at every required stop.', 'Derive exactly five unique Gridville edges from LocalDegreeBounds and support rows, without using CandidateTour, TourStop, or TourLeg as antecedents.', 'Local degree bounds identify edges independently at stops, but their deduplicated union is not a first-class object.', 'Derived 5 unique edges [''edge-a-b'', ''edge-a-e'', ''edge-b-c'', ''edge-c-d'', ''edge-d-e''] at total cost 14; no CandidateTour/TourStop/TourLeg row was an antecedent.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

