VALUES ('tsp-loop-593', 593, 'Non-tight twin-triangles fixture', 'CLOSED', 'tsp-rule-non-tight-lower-bound-counterexample', 'Non-tight twin-triangles fixture', 'Twin triangles: certified degree-two lower bound 6, feasible candidate cost 24, selected component count 2, proper subtours 2; no optimality or reconstruction certificate emitted.', 'Implement generic degree-two forcing on a sparse availability fixture.', 'Represent six stops in two cheap triangles with expensive crossings; certify lower bound 6, candidate cost 24, two selected components, and no optimality or route-reconstruction certificate.', 'The only positive fixture has a tight degree-two lower bound, so failure behavior is not represented.', 'Twin triangles: certified degree-two lower bound 6, feasible candidate cost 24, selected component count 2, proper subtours 2; no optimality or reconstruction certificate emitted.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

