VALUES ('tsp-loop-595', 595, 'Forbidden-edge propagation', 'CLOSED', 'tsp-rule-forbidden-edge-propagation', 'Forbidden-edge propagation', 'Forbade sparse B-D by degree saturation and twin WA-WC by proper-subtour prevention; both decisions are deterministic and branch-free.', 'Contract neighborhood internals into finite boundary states.', 'Forbid the sparse B-D chord by degree saturation and forbid a twin-triangle closing edge because it would close a proper subtour, with replayable reason codes.', 'Forced edges do not yet emit deterministic forbidden-edge consequences or premature-subtour exclusions.', 'Forbade sparse B-D by degree saturation and twin WA-WC by proper-subtour prevention; both decisions are deterministic and branch-free.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-596', 596, 'Neighborhood boundary-state contraction v0', 'CLOSED', 'tsp-rule-neighborhood-boundary-state', 'Neighborhood boundary-state contraction v0', 'Each twin-triangle neighborhood contracts six raw internal orders to three undirected boundary states (50%); paired composition contracts 36 combinations to nine (75%) with cost-preserving path witnesses.', 'Generalize boundary-state soundness across non-triangular clusters and then branch only on residual city-level ambiguity.', 'For each three-stop twin-triangle neighborhood, derive three undirected entry/exit Hamiltonian-path states, reduce six internal orders to three states, and reduce 36 paired internal orders to nine paired boundary-state combinations.', 'Neighborhood rows are geographic labels only; no executable entry/exit path states or contraction certificate exists.', 'Each twin-triangle neighborhood contracts six raw internal orders to three undirected boundary states (50%); paired composition contracts 36 combinations to nine (75%) with cost-preserving path witnesses.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-597', 597, 'Convergence prediction', 'CLOSED', 'tsp-rule-predicate-invention', 'Convergence Prediction', 'The convergence hypothesis is now versioned data, explicitly exploratory and not a theorem.', 'Derive the explicit predicate basis and map the surface vocabulary onto it.', 'Record the working prediction, baseline thirty-two surface predicates, target eight-predicate basis, and DAG-based predicate-invention method without claiming a theorem.', 'Forty physical tables expose at least thirty-two recurring surface predicates, but no explicit convergence hypothesis or semantic compression baseline is recorded.', 'Recorded a thirty-two-surface-predicate baseline, an eight-predicate target, and the prediction that DAG inference will invent derived predicates while the primitive basis stabilizes.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-598', 598, 'Eight-predicate basis', 'CLOSED', 'tsp-rule-predicate-invention', 'Predicate Basis', 'Predicate basis = {MEMBERSHIP, INCIDENCE, CARDINALITY, ORDER, WEIGHT, COMMITMENT, CONNECTIVITY, PROVENANCE}; measured semantic compression is 75%.', 'Collapse edge-decision vocabulary into one ordered commitment concept.', 'Represent exactly eight canonical primitives and map all thirty-two baseline surface predicates to finite basis expressions.', 'The convergence prediction is recorded, but the candidate primitive vocabulary and surface-to-basis map do not exist.', 'Mapped thirty-two recurring surface predicates to eight canonical primitives; historical names remain queryable projections rather than independent primitives.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-599', 599, 'Edge commitment lattice', 'CLOSED', 'tsp-rule-predicate-invention', 'Commitment Lattice', 'Gridville selections have rank 1 and CURRENT_WITNESS scope; sparse forced edges have rank 2 and ALL_FEASIBLE_TOURS scope; no epistemic upgrade was hidden.', 'Collapse degree checks, local bounds, and forcing into one incidence budget.', 'Project all edge statuses onto one commitment rank, polarity, necessity scope, and provenance representation without conflating selected with forced.', 'UNKNOWN, SELECTED, FORCED, FORBIDDEN, CONTRADICTED, and SUPERSEDED are separate surface statuses split across edge-state and constraint-decision projections.', 'Collapsed edge-state and constraint-decision vocabulary into a commitment lattice with rank, polarity, necessity scope, and provenance.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-600', 600, 'Incidence budget', 'CLOSED', 'tsp-rule-predicate-invention', 'Incidence Budget', 'All five Gridville and all six twin-triangle stops have required incidence 2, observed incidence 2, and incidence defect 0; connectivity remains a separate coordinate.', 'Lift local incidence defects into a global multi-coordinate defect vector.', 'Represent required incidence, observed incidence, and incidence defect uniformly for every Gridville and twin-triangle stop.', 'Cycle degree, selected degree, remaining degree, local lower-bound incidence, and forcing applicability are represented as separate concepts.', 'Projected local degree bounds, cycle degree, selected degree, and forcing applicability onto one incidence budget.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-601', 601, 'Defect vector', 'CLOSED', 'tsp-rule-predicate-invention', 'Defect Vector', 'Gridville vector = 0|0|0|0; twin local two-factor vector = 0|1|2|18, locating the exact unresolved geometry without inventing a new primitive.', 'Derive the minimum crossing demand exposed by the twin component defect.', 'Represent incidence, connectivity, boundary, and cost defects as one vector and distinguish zero-defect Gridville from twin triangles.', 'Degree violations, connected-component count, boundary crossings, and cost gaps are separate acceptance surfaces.', 'Collapsed incidence violations, component excess, missing boundary crossings, and bound gap into one defect vector.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-602', 602, 'Cut parity', 'CLOSED', 'tsp-rule-cut-parity', 'Cut Parity', 'Twin component cut: crossing count is even for every cycle and nonzero for connected coverage; therefore crossing count >= 2.', 'Turn mandatory crossings into an additive component-repair lower bound.', 'Derive that a Hamiltonian cycle crosses a nontrivial component cut a positive even number of times, hence at least twice.', 'Twin triangles exposes two selected components, but the mandatory number of crossings between them is not represented.', 'Derived a positive-even cut-crossing certificate for the two twin components, with minimum crossing demand two.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-603', 603, 'Component repair bound', 'CLOSED', 'tsp-rule-component-repair-bound', 'Component Repair Bound', 'Twin component repair adjustment is +18; the strengthened finite-instance lower bound is 24.', 'Compare the repaired lower bound with the feasible candidate upper bound.', 'Add two cost-ten crossings, release two cost-one internal edges, and certify an eighteen-unit repair adjustment and lower bound twenty-four.', 'Twin triangles has a certified local degree bound of six and a two-crossing requirement, but no composed global repair cost.', 'Composed the local degree bound with cut repair: 6 + (2 x 10) - (2 x 1) = 24.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-604', 604, 'Bound sandwich', 'CLOSED', 'tsp-rule-bound-equality-optimality', 'Bound Sandwich', 'The original degree-only bound remains recorded as non-tight; the composed component-repair bound equals the valid candidate and proves optimality only for tsp-twin-triangles-6.', 'Normalize supplied and reconstructed routes into one witness shape.', 'Close twin-triangle finite optimality by lower-bound/upper-bound equality while retaining the original non-tight local-bound counterexample.', 'Twin triangles has a repaired lower bound of twenty-four and a feasible candidate of cost twenty-four, but no finite optimality certificate.', 'Closed twin-triangle optimality by the sandwich 24 <= candidate cost 24 <= 24.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

