VALUES ('tsp-loop-624', 624, 'Coherence vector', 'CLOSED', 'tsp-rule-coherence-measurement', 'Coherence Vector', 'Loop-624 vector: atoms=3, operators=4, tables=45, open_frontier=2, named_concepts=75; local expansion remains allowed.', 'Test whether ATTACHMENT, VALUATION, and WARRANT are typed signatures of one relation.', 'Represent a coherence vector that records active atoms, active operators, physical-table delta, open frontier, named concepts, and the non-monotone expansion guardrail without collapsing those dimensions to an arbitrary scalar.', 'Loop 623 records local expansion as compatible with convergence, but the repository has no multidimensional measurement separating semantic basis size, physical size, open frontier, and named derived vocabulary.', 'Recorded semantic basis size, operator count, physical-table delta, open frontier, and named vocabulary as separate coherence coordinates.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-625', 625, 'Semantic arc', 'CLOSED', 'tsp-rule-semantic-arc-refinement', 'Semantic Arc', 'The three historical atoms remain distinct recoverable projections by ROLE, MEASURE, and MODALITY signatures; active atom count is one.', 'Prevent the generic arc from becoming a vacuous triple store by making its signatures explicit.', 'Introduce SEMANTIC_ARC(subject,label,target), reduce the three atoms to typed arc projections, preserve all historical definitions, and leave exactly one active relational atom.', 'ATTACHMENT, VALUATION, and WARRANT are three active ternary atoms with the same subject-label-target shape but different label and target sorts.', 'Collapsed ATTACHMENT, VALUATION, and WARRANT into one typed SEMANTIC_ARC relation.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

