VALUES ('tsp-loop-626', 626, 'Arc signature', 'CLOSED', 'tsp-rule-semantic-arc-refinement', 'Arc Signature', 'Attachment = ROLE arc, valuation = MEASURE arc, warrant = MODALITY arc; each historical atom has a distinct recovery filter, preventing a vacuous untyped triple-store collapse.', 'Certify that every registered concept remains recoverable from the current basis.', 'Record subject, label, and target sorts for attachment, valuation, and warrant projections and require distinct recoverable signatures for each historical atom.', 'A single generic arc can encode the three atoms syntactically, but their role, measure, and modality constraints are not yet recoverable as typed signatures.', 'Typed the semantic arc with explicit subject, label, and target sorts.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-627', 627, 'Recoverability witness', 'CLOSED', 'tsp-rule-semantic-arc-refinement', 'Recoverability Witness', 'Recoverability coverage is 79/79; no retired atom token remains in a current reduced definition.', 'Collapse closure and fixed point into one saturation operator.', 'Give every registered concept an explicit recovery expression over semantic arcs and operators, reject unreduced historical tokens, and preserve source-table provenance.', 'The arc signatures are represented, but lossless recovery of the historical vocabulary has not been certified across the concept registry.', 'Certified lossless recovery of the historical and derived vocabulary from semantic arcs plus the current operators.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-628', 628, 'Saturation operator', 'CLOSED', 'tsp-rule-warranted-rewrite', 'Saturation Operator', 'Reachability closure and no-change rule closure remain recoverable as distinct expansive saturation modes; active operators are Saturate, Aggregate, and Quotient.', 'Collapse aggregation and quotienting into one fiber-reduction operator.', 'Introduce SATURATE(seed,rewrite,termination_warrant), reduce closure and fixed point to explicit saturation modes, and preserve their historical operator identities.', 'CLOSURE and FIXPOINT are separate active operators although both repeatedly add warranted consequences until a stability condition holds.', 'Collapsed CLOSURE and FIXPOINT into the SATURATE operator.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-629', 629, 'Fiber reduction', 'CLOSED', 'tsp-rule-warranted-rewrite', 'Fiber Reduction', 'Count/sum/min/parity summaries and equivalence representatives remain recoverable reducer modes with explicit expansion warrants; active operator count is two.', 'Test whether saturation and fiber reduction are polarities of one rewrite operator.', 'Introduce FIBER_REDUCE(domain,key,reducer,expansion_warrant), reduce aggregate and quotient to reducer modes, and preserve all expansion and valuation semantics.', 'AGGREGATE and QUOTIENT are separate active operators although both group a domain by a key and replace each fiber with a warranted summary or representative.', 'Collapsed AGGREGATE and QUOTIENT into FIBER_REDUCE.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

