VALUES ('tsp-loop-630', 630, 'Warranted rewrite', 'CLOSED', 'tsp-rule-warranted-rewrite', 'Warranted Rewrite', 'Every transformation now exposes input, rule, polarity, output, and warrant; saturation and fiber reduction remain recoverable modes, and active operator count is one.', 'Make expansive and contractive rewrite polarity explicit.', 'Introduce WARRANTED_REWRITE(input,rule,polarity,output,warrant), reduce saturation and fiber reduction to rewrite modes, and leave exactly one active semantic operator.', 'SATURATE and FIBER_REDUCE remain separate operators even though both transform one semantic-arc state into another under an explicit warrant.', 'Collapsed SATURATE and FIBER_REDUCE into one WARRANTED_REWRITE operator.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-631', 631, 'Rewrite polarity', 'CLOSED', 'tsp-rule-warranted-rewrite', 'Rewrite Polarity', 'Closure/fixed point/saturation are recoverable as expansive modes; aggregate/quotient/fiber reduction as contractive modes; local expansion is explicitly compatible with coherent rewrite composition.', 'Certify the one-arc/one-rewrite basis for the represented domain.', 'Classify historical and current operators as EXPANSIVE, CONTRACTIVE, MIXED, or PARAMETRIC, with modes that recover closure, fixed point, aggregate, quotient, saturation, and fiber reduction.', 'The single rewrite operator is parametric, but the distinction between black-box internalization growth, saturation growth, and quotient contraction is not typed.', 'Typed expansive, contractive, mixed, and parametric rewrite modes.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-632', 632, 'One-arc one-rewrite basis', 'CLOSED', 'tsp-rule-semantic-arc-refinement', 'One-Arc/One-Rewrite Basis', 'Thirty-two baseline surfaces reduce to one active atom (96.88%); 87 registered concepts remain recoverable, historical bases remain versioned, and minimality is not claimed.', 'Stress the basis on a reusable region interface with three disconnected local components.', 'Certify one active atom and one active operator, recover every registered concept without old atom/operator tokens, preserve all prior certificates, and retain the non-claim of minimality or universality.', 'One active arc and one active rewrite have emerged incrementally, but lossless coverage, current-basis counts, and empirical scope are not yet certified.', 'Certified one active typed semantic arc and one active warranted rewrite for the current TSP domain.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-633', 633, 'Region interface', 'CLOSED', 'tsp-rule-region-interface', 'Region Interface', 'Region identity now carries two boundary ports, internal coverage, an ordered expansion witness kind, and a certified interface status; neighborhood versus component remains provenance.', 'Instantiate three cheap local regions in one complete nine-stop graph.', 'Add a common region-interface projection to existing quotient nodes without a new table and define ports, internal coverage, expansion witness, and interface status through semantic arcs.', 'Neighborhoods, components, and boundary fibers are quotient objects, but their shared port, coverage, valuation, and expansion contract is not represented as one region interface.', 'Normalized every existing quotient node through one region-interface projection.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-634', 634, 'Region triad', 'CLOSED', 'tsp-rule-region-interface', 'Region Triad', 'Nine valid local degree witnesses select nine internal edges of total cost nine; their union has degree two at every stop, three connected components, three proper subtours, and no route or optimality promotion.', 'Contract each triangle into a boundary-degree-two region quotient.', 'Represent a complete nine-stop graph partitioned into three cost-one triangles, three cost-ten ring crossings, expensive remaining crossings, nine valid local degree bounds, and a three-component local two-factor of cost nine.', 'Component repair has only been tested on two three-stop regions, so crossing demand and repair composition for more than two components are unmeasured.', 'Represented three cost-one local triangles inside one complete nine-stop weighted graph.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-635', 635, 'Region quotient', 'CLOSED', 'tsp-rule-region-interface', 'Region Quotient', 'Three quotient nodes expose nine total boundary states and eighteen expansion edges; each regional certificate records 6 directed orders to 3 reversal classes at cost two.', 'Express the global deficit as quotient incidence rather than fixture-specific component prose.', 'Represent three boundary-degree-two quotient nodes, three path states per region, explicit edge expansions, and one passing six-to-three contraction certificate per region.', 'The region-triad local two-factor has three components, but the components do not yet expose reusable path states and expansion witnesses.', 'Contracted each local triangle to a certified boundary-degree-two region quotient.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-636', 636, 'Quotient incidence budget', 'CLOSED', 'tsp-rule-boundary-handshake', 'Quotient Incidence Budget', 'Every stop retains internal degree two, every region requires external degree two and currently has zero, and the global profile records component count three with crossing deficit three. Cost coordinates remain explicitly unwitnessed at this stage.', 'Convert quotient degree demand into a minimum crossing-edge count.', 'Give each of three region nodes required boundary degree two, observed degree zero, and a shared global profile separating closed internal incidence from open quotient incidence.', 'Every local stop has degree two, yet the quotient graph has no external incidence; the resulting global defect is not represented in the common budget vocabulary.', 'Lifted the three-component defect into quotient incidence budgets.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-637', 637, 'Boundary handshake', 'CLOSED', 'tsp-rule-boundary-handshake', 'Boundary Handshake', 'Required quotient degree is 3 regions x 2 = 6; dividing by two endpoints per crossing certifies at least 3 inter-region edges.', 'Compose the crossing demand with insertion and release valuations.', 'Apply the handshake identity to the quotient: total boundary degree six divided by two endpoints per crossing requires at least three inter-region edges.', 'Three quotient nodes each require boundary degree two, but the number of inter-region edges forced by that demand is not yet derived.', 'Derived a three-edge crossing demand from the quotient boundary-degree handshake.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-638', 638, 'Region repair equation', 'CLOSED', 'tsp-rule-region-repair-equation', 'Region Repair Equation', 'The signed supplemental adjustment is +27; all contributing insertion and release terms are separately certified, and no route witness has yet been used to set the bound. The lower coordinate is witnessed; the feasible upper coordinate remains open until construction.', 'Construct the repaired cycle as a balanced edge exchange.', 'Certify 9 + 3*10 - 3*1 = 36 from a base term, three mandatory crossing insertions, and one necessary cost-one internal release per region.', 'The base degree-two lower bound is nine and crossing demand is three, but the signed cost of repairing three components is not represented.', 'Composed the three-region repair lower bound as 9 + 3*10 - 3*1 = 36.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-639', 639, 'Balanced edge exchange', 'CLOSED', 'tsp-rule-balanced-edge-exchange', 'Balanced Edge Exchange', 'Added=[''r3-edge-a1-c3'', ''r3-edge-a3-b1'', ''r3-edge-b3-c1'']; released=[''r3-edge-a1-a3'', ''r3-edge-b1-b3'', ''r3-edge-c1-c3'']; every stop has repaired degree two, component count is one, proper subtours are zero, and total cost is thirty-six. Released edges are superseded only for this witness, never silently forbidden globally. The connected degree-two exchange now supplies the cost-thirty-six feasible upper witness.', 'Project an ordered repair cycle without consuming a supplied candidate as antecedent.', 'Replace one internal edge per local triangle with the three cost-ten ring crossings, preserve every stop at degree two, and certify one connected nine-edge cycle of cost thirty-six.', 'The repair equation proves a lower value, but no structural object witnesses the three added and three released edges that preserve degree while joining the regions.', 'Constructed a connected nine-edge cycle by a balanced three-add/three-release exchange.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-640', 640, 'Repair cycle', 'CLOSED', 'tsp-rule-balanced-edge-exchange', 'Repair Cycle', 'Route A1-A2-A3-B1-B2-B3-C1-C2-C3-A1 has nine valid legs, zero defects, CandidateUsedAsAntecedent=false, and matches its downstream comparison candidate.', 'Close finite optimality by equality with the region repair bound.', 'Reconstruct the nine-stop cycle from the repaired edge set, emit ordered steps and a comparison candidate of cost thirty-six, and record CandidateUsedAsAntecedent=false.', 'The balanced-exchange edge set is a certified cycle, but it has no ordered reconstruction or normalized route witness.', 'Reconstructed the balanced-exchange cycle as an ordered nine-stop route of cost thirty-six.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-641', 641, 'Region bound sandwich', 'CLOSED', 'tsp-rule-bound-equality-optimality', 'Region Bound Sandwich', 'Certified lower bound 36 equals valid reconstructed witness cost 36. The certificate is scoped to tsp-three-regions-9 and does not claim a general k-region repair theorem.', 'Stress the value proof on an instance with two distinct optimal route classes.', 'Certify the reconstructed cost-thirty-six cycle as optimal for tsp-three-regions-9 by lower-bound equality, without claiming a general k-region theorem.', 'The three-region lower bound and valid reconstructed cycle both equal thirty-six, but no finite optimality certificate joins them.', 'Closed finite optimality for the three-region nine-stop fixture at cost thirty-six.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-642', 642, 'Optimal face', 'CLOSED', 'tsp-rule-optimal-face', 'Optimal Face', 'The degree-two lower-bound ingredients total eight before double-counting, and the three valid Hamiltonian witnesses have raw costs [4, 4, 6]; value and witness identity remain open.', 'Certify the optimum value while leaving route identity non-unique.', 'Represent a complete four-stop graph with degree-two lower bound four, two non-reversal-equivalent Hamiltonian cycles of cost four, and a third Hamiltonian cycle of cost six.', 'Every represented positive fixture has one distinguished optimal route, so optimal value and optimal witness identity have not been separated.', 'Represented a four-stop optimal face with two non-reversal-equivalent cost-four cycles and one cost-six control cycle.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-643', 643, 'Value choice split', 'CLOSED', 'tsp-rule-optimal-face', 'Value/Choice Split', 'Both A-B-C-D-A and A-C-B-D-A carry passing finite optimality certificates; A-B-D-C-A costs six. ValueStatus=CLOSED_AT_4, ChoiceStatus=OPEN_TWO_OPTIMAL_CLASSES, branch decisions=0.', 'Name and measure the residual optimal-witness orbit.', 'Attach passing optimality certificates to both cost-four cycles and represent value status CLOSED while choice status remains a two-alternative non-reversal orbit.', 'The optimal-face fixture has two equal-cost witnesses, but proof status and witness-selection status are not independently represented.', 'Closed the optimum value at four while preserving two distinct optimal witness classes.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-644', 644, 'Choice orbit', 'CLOSED', 'tsp-rule-optimal-face', 'Choice Orbit', 'Initial route classes=3, surviving optimal classes=2, residual ambiguity=2, certified value=4, branch decisions=0. The remaining orbit is not an unresolved optimum-value defect.', 'Decide exactly when a branch is warranted after value closure.', 'Record three initial route classes, two surviving optimal classes, certified value four, zero mathematical branch decisions, and residual choice-orbit size two.', 'The two optimal witnesses are recorded, but residual ambiguity is not classified as a value-preserving orbit distinct from unresolved optimality.', 'Named and measured the two-member value-preserving optimal witness orbit.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-645', 645, 'Branch warrant', 'CLOSED', 'tsp-rule-branch-warrant', 'Branch Warrant', 'BranchPurpose=VALUE_PROOF is rejected because value four is already certified. Representative choice remains conditional on an external tie-break policy; DecisionCount=0 and the two-member orbit is preserved.', 'Measure the second convergence event across the arc/rewrite basis and both stress fixtures.', 'Reject mathematical branching for value proof, require an external tie-break policy before representative selection, and emit a replayable rejected-branch event with zero branch decisions.', 'A residual choice orbit exists, but the system does not distinguish a branch needed for proof from a conditional tie-break needed only to select one representative.', 'Rejected mathematical branching for the value-closed optimal face.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-646', 646, 'Coherence event two', 'CLOSED', 'tsp-rule-coherence-measurement', 'Coherence Event II', 'Named concepts=101 and witness rows increased, but active atoms=1, active operators=1, tables=45, recoverability is complete, proof branch decisions=0, and no universal convergence or TSP-complexity theorem is claimed.', 'Stress the one-arc/one-rewrite basis on heterogeneous regions and only branch when a warranted policy or unresolved value defect remains.', 'Certify one active arc, one active rewrite, unchanged physical-table count, explicit local expansion, three-region optimum thirty-six, optimal-face value four with choice orbit two, and zero branch decisions for value proof.', 'The pass has coined new machinery and added many witness rows, but its effect on basis size, physical schema, trust, multi-region repair, and residual choice has not been summarized.', 'Certified the second coherence event: one typed arc, one warranted rewrite, forty-five physical tables, three-region optimum thirty-six, and optimal-face value four with a two-member choice orbit.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-647', 647, 'Independent loop-646 seal', 'CLOSED', 'tsp-rule-exact-oracle-calibration', 'Instrument Seal II', 'One active Semantic Arc, one active Warranted Rewrite, three-region optimum 36, optimal-face value 4 with choice orbit 2, and all universal nonclaims agree.', 'Freeze the current semantic basis for a held-out campaign.', 'Recompute the loop-646 basis and finite fixture claims from canonical rows, preserve the nonclaims, and close a raw-witness prerequisite for calibration.', 'Loop 646 has a successful execution certificate, but the held-out campaign has not independently rechecked its raw one-arc/one-rewrite, three-region, and optimal-face witnesses.', 'Sealed the loop-646 execution state as the held-out campaign prerequisite.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-648', 648, 'Frozen semantic basis', 'CLOSED', 'tsp-rule-heldout-calibration', 'Basis Freeze', 'The primitive budget is zero unless a loop records a basis falsification; derived predicate invention continues normally.', 'Declare the exact-oracle trust contract.', 'Freeze SEMANTIC_ARC and WARRANTED_REWRITE as the campaign basis; require any new primitive to be accompanied by a recorded falsification and basis-revision event.', 'The one-arc/one-rewrite basis is empirical but later loops could silently add primitives while claiming held-out support.', 'Froze the one-arc/one-rewrite basis for held-out evaluation.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

