VALUES ('tsp-loop-649', 649, 'Exact-oracle contract', 'CLOSED', 'tsp-rule-exact-oracle-calibration', 'Exact Oracle Contract', 'The oracle is exact for the declared finite normalization, but remains calibration evidence rather than an automatic structural proof-status upgrade.', 'Canonicalize tours modulo depot fixing and reversal.', 'Add calibration fields for exact class count, feasible classes, optimum, optimal orbit, lower-bound gap, deterministic residue, branch warrant, and oracle checksum without treating enumeration as a structural proof.', 'Exact route enumeration exists only as an external implementation idea; its scope, normalization, and status are not canonical fields.', 'Declared the exact small-instance oracle and its trust boundary.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

